// // This module calculates the parity of an m-bit input array A, where m is a parameter set to 163 by default. The output O will be high if the number of high bits in A is even and low if the number of high bits is odd.
module top_module(O,A);parameter m=163; 
  input wire[0:m-1] A; 
  output wire O; 
  assign O = ^A; 
 endmodule
